input.command:
powershell -Command "
$dirs = @('C:\Users\25789\Desktop','C:\Users\25789\Downloads','C:\Users\25789\Documents','C:\Users\25789\Videos','C:\Users\25789\Music')
foreach ($dir in $dirs) {
    Write-Host ('=== ' + $dir.Replace('C:\Users\25789\','') + ' ===')
    $groups = Get-ChildItem $dir -File -Recurse -ErrorAction SilentlyContinue | Group-Object Name | Where-Object { $_.Count -gt 1 }
    if ($groups) {
        foreach ($g in $groups) {
            $size = ($g.Group | Measure-Object Length -Sum).Sum
            Write-Host (\"  $($g.Name)  x$($g.Count)  $($size/1KB -as [int])KB\")
        }
    } else {
        Write-Host '  无重复文件'
    }
    Write-Host ''
}"

